import { execFileSync } from 'node:child_process';
import { resolve } from 'node:path';

/** packages/web-ui/tsconfig.json extends ./.svelte-kit/tsconfig.json
 *  which is generated by svelte-kit sync. Without it, vite:oxc fails
 *  to transform any web-ui test file. Run sync once before the suite. */
export default function setup(): void {
  execFileSync('pnpm', ['exec', 'svelte-kit', 'sync'], {
    cwd: resolve('packages/web-ui'),
    stdio: 'inherit',
  });
}
